using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using System.IO;
using System.Linq;

namespace YourNamespace
{
    public class HomeController : Controller
    {
        private readonly IWebHostEnvironment _environment;

        public HomeController(IWebHostEnvironment environment)
        {
            _environment = environment;
        }

        [HttpPost]
        public IActionResult UploadAvatar(IFormFile file)
        {
            if (file.Length > 0)
            {
                string fileName = $"avatar-{Guid.NewGuid()}.{Path.GetExtension(file.FileName)}";
                var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads");
                if (!Directory.Exists(uploadsFolder)) Directory.CreateDirectory(uploadsFolder);
                using (var stream = new FileStream(Path.Combine(uploadsFolder, fileName), FileMode.Create))
                {
                    file.CopyTo(stream);
                }
                return Json(new { path = $"/uploads/{fileName}" });
            }
            return BadRequest();
        }

        [HttpPost]
        public IActionResult UploadDocument(IFormFile file)
        {
            var allowedTypes = new[] { ".png", ".jpg", ".jpeg", ".bmp", ".pdf", ".docx", ".xlsx" };
            if (file.Length > 0 && allowedTypes.Any(ext => string.Equals(Path.GetExtension(file.FileName), ext, StringComparison.OrdinalIgnoreCase)))
            {
                string fileName = $"document-{Guid.NewGuid()}.{Path.GetExtension(file.FileName)}";
                var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads");
                if (!Directory.Exists(uploadsFolder)) Directory.CreateDirectory(uploadsFolder);
                using (var stream = new FileStream(Path.Combine(uploadsFolder, fileName), FileMode.Create))
                {
                    file.CopyTo(stream);
                }
                return Json(new { path = $"/uploads/{fileName}" });
